import{Alerter}from"./index.min.js";class PostEditor{constructor(){this.alerter=new Alerter,this.postID=document.getElementById("content-container").dataset.postId,this.editButton=document.getElementById("edit-mode-button"),this.editCancelButton=document.getElementById("post-edit-box-cancel"),this.commentsBox=document.getElementById("comments-box"),this.infoBox=document.getElementById("info-box"),this.editorBox=document.getElementById("edit-box"),this.saveButton=document.getElementById("post-edit-box-save"),this.parentIdInput=document.getElementById("post-edit-parent"),this.postRatingInput=document.getElementById("post-edit-rating"),this.postSourceInput=document.getElementById("post-edit-source"),this.postDescription=document.getElementById("post-edit-desc"),this.postTags=document.getElementById("post-edit-tags"),this.postOldTags=document.getElementById("post-edit-old-tags"),this.editButton.onclick=()=>{this.toggleEditMode()},this.editCancelButton.onclick=()=>{this.toggleEditMode()},this.saveButton.onclick=()=>{this.saveEdits()}}toggleEditMode(){this.commentsBox.style.display="none"==this.commentsBox.style.display?"block":"none",this.infoBox.style.display="none"==this.infoBox.style.display?"block":"none",this.editorBox.style.display="flex"==this.editorBox.style.display?"none":"flex",this.editButton.innerText="Edit Post"==this.editButton.innerText?"Exit Edit Mode":"Edit Post"}saveEdits(){let t={url:"/api/v1/post",method:"PUT",headers:{"Content-Type":"application/json"},data:JSON.stringify({id:this.postID,description:this.postDescription.value,tags:this.postTags.value,old_tags:this.postOldTags.value,rating:this.postRatingInput.value,source:this.postSourceInput.value})};$.ajax(t).done((function(t){location.reload()}))}}export{PostEditor};